/**
 * TypeScript mirror of the cache-hit / marginal-fold slice of
 * `lean/Lean/ForkRaceFoldTheorems/CacheObservation.lean` (zero-marginal-fold on hit).
 *
 * Not a proof — runtime bookkeeping and tests only.
 */

/** `PositiveFoldWork` in Lean: natural strictly greater than zero. */
export interface PositiveFoldWork {
  readonly val: number;
}

export type CacheQueryResolution =
  | { readonly kind: 'hit' }
  | { readonly kind: 'cold_miss'; readonly work: PositiveFoldWork }
  | { readonly kind: 'stale_miss'; readonly work: PositiveFoldWork };

/** Lean `marginal_fold_work`. */
export function marginalFoldWork(q: CacheQueryResolution): number {
  switch (q.kind) {
    case 'hit':
      return 0;
    case 'cold_miss':
    case 'stale_miss':
      return q.work.val;
  }
}

/**
 * Lean `marginal_fold_zero_iff_hit` — boolean check for concrete resolutions.
 * Returns whether `marginalFoldWork(q) === 0` matches `q.kind === 'hit'`.
 */
export function marginalFoldZeroIffHit(q: CacheQueryResolution): boolean {
  const m = marginalFoldWork(q);
  return (m === 0) === (q.kind === 'hit');
}
